<template>
  <div class="Login">
    <div class=" mb-5">
      <!-- image -->
      <div style="max-height: 260px">
          <img src="@/assets/Home.svg" alt="intro" style="width: 100%; height:90%" />
      </div>
      <div class="close">
        <router-link to="/">
      <i class="fa fa-times shadow" ></i>
      </router-link>
      </div>
      <!-- greeting -->
      <div class="row">
        <div class="col">
          <!-- <span style="font-size: 1rem">{{ getGreeting }}</span> -->
          <!-- <span style="font-size: 1.2rem">Good {{ getTimeOfDay }}</span> -->
          <!-- <br /> -->
          <b v-if="!verify"
            style="font-size:2rem;text-overflow:ellipsis;width:100%;white-space:nowrap;overflow:hidden;display:block"
          >Welcome!</b>
          <b v-else
            style="font-size:2rem;text-overflow:ellipsis;width:100%;white-space:nowrap;overflow:hidden;display:block"
          >Almost there!</b>
          <span v-if="!verify">Please enter number to continue</span>
          <span v-else class="text-justify mx-2">Please verify your number by entering the six digit that has been sent to your phone</span>
          <br />
        </div>
      </div>
<div class="container">
  <form>
      <div class="row m-0 mt-4" >
        <div class="col-12" v-if="!verify">
          <input
            type="text"
            name="mobile-inp"
            id="mobile-inp"
            class="form-inp"
            placeholder="mobile"
            v-model.trim="form.mobile"
            required
          />
        </div>
        <div class="col-12" v-else>
          <input
            type="text"
            name="pass-inp"
            id="pass-inp"
            class="form-inp"
            placeholder="code"
            v-model.trim="form.password"
            required
          />
        </div>
        <div class="col-12" v-if="!verify">
          <div class="row justify-content-between px-3">
              <small  style="font-size: 0,8rem">Don't have an account? <router-link to="/signup" class="text-info">Sign Up</router-link></small>
              <small  style="font-size: 0,8rem">
                <!-- <a href class="text-info">Forgot your password?</a> -->
              </small>
            </div>
        </div>
        <div class="col-12 mt-3" v-else>
          <div class="row justify-content-between px-3">
              <small  @click="changeNumber()"> <router-link to="#" class="text-info">Change number</router-link></small>
              <small  @click="validateForm()"> <router-link to="#" class="text-info">Send code again</router-link></small>
            </div>
        </div>
        <div class="col-12 mt-5 text-right">
          <button type="submit" @click.prevent="login" v-if="!verify" class="loginBtn" :disabled="loading">
                      <i
                        v-if="loading"
                        :class="['fa', 'fa-spin', 'fa-spinner', loading?'loading-width':'']"
                      ></i>
                      <template v-else><i class="fa fa-arrow-right"></i></template>
          </button>
          <button type="submit" @click="goLive" v-if="verify" class="btn btn-info">
                     Verify Code
          </button>
        </div>
      </div>
      </form>
</div>
    </div>
