</template>

<script>
import http from '@/network/Base.js'
import login from '@/network/user/signin.js'
import moment from "moment";

export default {
  name: "login",
  components: {},
  data() {
    return {
      loading: false,
      verify: false,
      form: {
        mobile: "",
        password: ""
      },
      user: '',
      code: ''
    };
  },
  computed: {
    getTimeOfDay() {
      const hr = new Date().getHours();
      if (hr < 12) return "Morning";
      else if (hr < 17) return "Afternoon";
      else return "Evening";
    }
  },
  methods: {
    goLive(){
      if (this.code.code == this.form.password) {
         this.$store.commit('authStore/setLoggedIn', true)
                this.$store.commit('authStore/setUserInfo', this.user)
                this.$store.commit('authStore/setId', this.user.id)
                this.$router.push({ path: "/" })
                // this.verify = true
            } else {
                // this.$swal('Login Error', "Incorrect email & password!", 'error')
                this.$snotify.error("Code incorrect")

                // e.loading = false
            }
    },
    changeNumber(){
      this.verify = false
    },
    validateForm() {
      // let userlog = user
       http().post('/user/sendotpcode', {
            sz_phoneno: this.form.mobile,
            phone: this.form.mobile,
        }).then((data) => {
            // this.$Progress.finish()
            let empty = null

            let userobject = null;
            userobject = data.data
            console.log(userobject)
            if (userobject.status == true) {
                this.code = userobject
                this.verify = true
            } else {
                // this.$swal('Login Error', "Incorrect email & password!", 'error')
                this.$snotify.error("Code wasn't sent")
                // e.loading = false
            }
        }).catch(error => {
            console.log(error);
            // this.$Progress.finish()
            if (error.response) {
                // this.$Progress.finish()
                if (error.response.status === 500) {
                    //    return this.$swal('System Error', 'Error occurred during authentication processing!', 'error')
                    return this.$snotify.error('An error occured whiles authenticating')
                } else if (error.response.status === 200) {
                    // this.$swal('Login Error', "Incorrect email & password!", 'error')
                    return this.$snotify.error('Incorrect number')
                }
                // return this.$swal('Error', 'Incorrect email & password!!', 'error')
                return this.$snotify.error('Incorrect number')
            }
            // return this.$swal('Error', 'Please check you internet connection', 'error')
            return this.$snotify.error('Could not sign you in. Check your internet connection!')
        }).finally(() => {
            this.isSignedIn = false
            this.loading = false
        })
    },
    login() {
      this.loading = true
      // login.userSignIn(this, http(), this.form);
      http().post('/patient/checkexistence', {
            sz_phoneno: this.form.mobile,
        }).then((data) => {
            // this.$Progress.finish()
            let empty = null
               this.loading = false

            let userobject = null;
            userobject = data.data
            if (userobject) {
              this.user = userobject
                this.validateForm()
            } else {
                // this.$swal('Login Error', "Incorrect email & password!", 'error')
                this.$snotify.error('Please you don\'t have an account with us')
            }
        }).catch(error => {
            console.log(error);
               this.loading = false

            // this.$Progress.finish()
            if (error.response) {
                // this.$Progress.finish()
                if (error.response.status === 500) {
                    //    return this.$swal('System Error', 'Error occurred during authentication processing!', 'error')
                    return this.$snotify.error('An error occured whiles authenticating')
                } else if (error.response.status === 200) {
                    // this.$swal('Login Error', "Incorrect email & password!", 'error')
                    return this.$snotify.error('Incorrect number!')
                }
                // return this.$swal('Error', 'Incorrect email & password!!', 'error')
                return this.$snotify.error('Incorrect number')
            }
            // return this.$swal('Error', 'Please check you internet connection', 'error')
            return this.$snotify.error('Could not sign you in. Check your internet connection!')
        }).finally(() => {
            this.isSignedIn = false
            this.loading = false
        })
    }
  }
};
</script>

